import sys, urllib.request, json
coins = sys.argv[1:] if len(sys.argv) > 1 else ['bitcoin', 'ethereum', 'solana']
ids = ','.join(coins)
url = f'https://api.coingecko.com/api/v3/simple/price?ids={ids}&vs_currencies=usd&include_24hr_change=true'
try:
    req = urllib.request.Request(url, headers={'User-Agent': 'VANTIS/1.0'})
    with urllib.request.urlopen(req, timeout=10) as r:
        data = json.load(r)
    out = {}
    for c, v in data.items():
        out[c] = {'usd': v.get('usd'), 'change_24h': round(v.get('usd_24h_change', 0), 2)}
    print(json.dumps(out))
except Exception as e:
    print(json.dumps({'error': str(e)}))

import json, subprocess, sys

def run(cmd):
    try:
        return subprocess.check_output(cmd, shell=True, text=True, timeout=5).strip()
    except Exception:
        return ''

result = {}

# CPU
cpu = run("grep 'cpu ' /proc/stat")
if cpu:
    parts = cpu.split()[1:]
    idle = int(parts[3])
    total = sum(int(x) for x in parts)
    result['cpu_pct'] = round((1 - idle / total) * 100, 1) if total else 0

# Memory
mem = run('free -m')
if mem:
    for line in mem.splitlines():
        if line.startswith('Mem:'):
            p = line.split()
            result['mem_total_mb'] = int(p[1])
            result['mem_used_mb'] = int(p[2])
            result['mem_free_mb'] = int(p[3])

# Disk
df = run('df -h /')
if df:
    lines = df.strip().splitlines()
    if len(lines) > 1:
        p = lines[1].split()
        result['disk'] = {'total': p[1], 'used': p[2], 'free': p[3], 'pct': p[4]}

# Top 5 processes by memory
ps = run("ps aux --no-header --sort=-%mem | head -5 | awk '{print $11, $3, $4}'")
if ps:
    result['top_procs'] = [{'cmd': l.split()[0], 'cpu': l.split()[1], 'mem': l.split()[2]} for l in ps.splitlines() if l.split()]

print(json.dumps(result))

import sys, subprocess, json, os
path = sys.argv[1] if len(sys.argv) > 1 else os.getcwd()
def git(args):
    try:
        return subprocess.check_output(['git', '-C', path] + args, text=True, timeout=10, stderr=subprocess.DEVNULL).strip()
    except Exception:
        return ''
result = {
    'branch': git(['rev-parse', '--abbrev-ref', 'HEAD']),
    'status': git(['status', '--short']),
    'log': git(['log', '--oneline', '-10']),
    'remotes': git(['remote', '-v']),
}
print(json.dumps(result))

import sys, urllib.request, json, os
repo = sys.argv[1] if len(sys.argv) > 1 else 'torvalds/linux'
token = os.environ.get('GITHUB_TOKEN', '')
headers = {'User-Agent': 'VANTIS/1.0', 'Accept': 'application/vnd.github.v3+json'}
if token:
    headers['Authorization'] = f'Bearer {token}'
def gh(endpoint):
    try:
        req = urllib.request.Request(f'https://api.github.com{endpoint}', headers=headers)
        with urllib.request.urlopen(req, timeout=10) as r:
            return json.load(r)
    except Exception as e:
        return {'error': str(e)}
info = gh(f'/repos/{repo}')
commits = gh(f'/repos/{repo}/commits?per_page=5')
result = {
    'repo': repo,
    'description': info.get('description'),
    'stars': info.get('stargazers_count'),
    'forks': info.get('forks_count'),
    'open_issues': info.get('open_issues_count'),
    'language': info.get('language'),
    'recent_commits': [{'sha': c.get('sha','')[:7], 'msg': c.get('commit',{}).get('message','').splitlines()[0]} for c in (commits if isinstance(commits, list) else [])][:5]
}
print(json.dumps(result))

import subprocess, json
def run(cmd):
    try:
        return subprocess.check_output(cmd, shell=True, text=True, timeout=10, stderr=subprocess.DEVNULL).strip()
    except Exception:
        return ''
ps = run("docker ps --format '{{.ID}}\t{{.Names}}\t{{.Image}}\t{{.Status}}\t{{.Ports}}'")
if not ps:
    print(json.dumps({'error': 'Docker not available or no containers running'}))
else:
    containers = []
    for line in ps.splitlines():
        parts = line.split('\t')
        containers.append({'id': parts[0] if parts else '', 'name': parts[1] if len(parts)>1 else '', 'image': parts[2] if len(parts)>2 else '', 'status': parts[3] if len(parts)>3 else '', 'ports': parts[4] if len(parts)>4 else ''})
    print(json.dumps({'containers': containers, 'count': len(containers)}))
